	// Local commands (shell escapes, /context, etc.) write user events but
	// don't trigger agent turns. Skip them to avoid affecting state detection.
	if eventType == "user" {
		if isMeta, ok := raw["isMeta"].(bool); ok && isMeta {
			ev.Skip = true
			return ev
